-- Backfill the `description` for every expense category. Descriptions are fed to
-- the AI classifier verbatim ("- {name} — {description} (aliases: …)"), so each is
-- a short disambiguating note: what belongs here and which neighbour to prefer
-- otherwise. Runs after 0006/0007, so all 26 current categories exist. Matched by
-- name, so it is idempotent (re-run sets identical text) and a no-op on prod once
-- applied. New categories added later must ship their own description.

UPDATE "categories" AS c SET "description" = v.descr
FROM (VALUES
  ('Продукты', 'Еда и продукты питания из магазинов (супермаркеты, Пятёрочка, Ярче и т.п.). Готовая еда в кафе и доставка — НЕ сюда, а в «Кафе, доставка, фастфуд».'),
  ('Здоровье (врачи и процедуры)', 'Врачи, приёмы, обследования и медицинские процедуры (стоматолог, ЛОР, УЗИ, анализы, диагностика, нейропсихолог). Лекарства из аптеки — в «Аптека».'),
  ('Подарки', 'Только подарки и презенты другим людям. Покупки на маркетплейсах (Ozon, Wildberries, WB) НЕ сюда — их относят к категории по сути товара.'),
  ('Кафе, доставка, фастфуд', 'Питание вне дома и доставка готовой еды: кафе, рестораны, фастфуд, пицца, хот-доги, шаурма, чаевые. Продукты из магазина — в «Продукты».'),
  ('Ремонт машины и эксплуатация', 'Ремонт и обслуживание автомобиля: автосервис, СТО, запчасти, шины, установка оборудования (сигнализация, багажник). Топливо и платные дороги — в «Бензин и расходники на машину».'),
  ('Аптека', 'Лекарства, витамины и товары из аптеки. Приёмы врачей и процедуры — в «Здоровье (врачи и процедуры)».'),
  ('Путешествия и билеты', 'Поездки и отдых: билеты, перелёты, отели и гостиницы, бронирования. Городское такси — в «Такси».'),
  ('Бензин и расходники на машину', 'Топливо (бензин, газ), заправка, платные дороги (Платон, автодороги), парковка, мелкие расходники. Ремонт и запчасти — в «Ремонт машины и эксплуатация».'),
  ('Спорт взрослых', 'Спорт и фитнес для взрослых: бассейн, тренажёрный зал, тренировки, футбол, абонементы. Детские секции — в «Кружки и секции детей».'),
  ('Садик', 'Оплата детского сада.'),
  ('Кружки и секции детей', 'Детские кружки, секции и занятия (баскетбол, кикбоксинг и т.п.). Спорт для взрослых — в «Спорт взрослых».'),
  ('Сервисы, интернет, связь', 'Подписки и цифровые сервисы, интернет, мобильная связь, хостинг, домены, серверы, прокси, донаты и подписки на блогеров (Boosty, Бусти).'),
  ('ЖКХ', 'Коммунальные платежи: квартплата, электричество, вода, газ, отопление.'),
  ('Такси', 'Поездки на такси (Яндекс Такси, Uber и т.п.).'),
  ('Ипотека', 'Платежи по ипотеке и кредитам.'),
  ('Развлечения (кино, театр)', 'Досуг и развлечения: кино, театр, концерты, шоу, выставки.'),
  ('Услуги (стрижка, эпиляция)', 'Бытовые и персональные услуги: стрижка, парикмахер, маникюр, эпиляция, массаж, ремонт вещей. Косметика и уходовые товары — в «Товары для красоты».'),
  ('Хобби', 'Хобби, увлечения, обучение и курсы (ораторское мастерство, маркетинг и т.п.).'),
  ('Другое', 'Крайний случай: использовать ТОЛЬКО если трата не подходит ни к одной другой категории. Это не свалка — сначала ищи конкретную категорию.'),
  ('Ремонт и обустройство квартиры', 'Ремонт, стройка и обустройство жилья: стройматериалы, мебель, инструменты, строй-контроль. Хозтовары и бытовая химия — в «Товары для дома».'),
  ('Детские товары', 'Товары для детей: детская одежда, игрушки, подгузники, коляски, детское питание. Взрослая одежда — в «Одежда и обувь».'),
  ('Товары для дома', 'Хозтовары, бытовая химия, посуда, товары для дома (Фикс Прайс и т.п.). Мебель и ремонт — в «Ремонт и обустройство квартиры».'),
  ('Одежда и обувь', 'Одежда и обувь для взрослых. Детская одежда — в «Детские товары».'),
  ('Товары для красоты', 'Косметика, парфюмерия, уходовые и бьюти-товары (крем, макияж, шампунь, духи). Услуги (стрижка, маникюр) — в «Услуги (стрижка, эпиляция)».'),
  ('Помощь родителям', 'Деньги и помощь родителям, бабушкам и дедушкам (переводы, покупки для них).'),
  ('Дача', 'Расходы на дачу и загородный участок: огород, сад, рассада, теплица, дачное хозяйство.')
) AS v(name, descr)
WHERE c."name" = v.name AND c."description" IS DISTINCT FROM v.descr;
